var maxScore = function(s) {
    const totalOnes = s.split('').filter(c => c === '1').length;
    let zerosLeft = 0, onesLeft = 0, best = 0;
    for (let i = 0; i < s.length - 1; i++) {
        if (s[i] === '0') zerosLeft++;
        else onesLeft++;
        best = Math.max(best, zerosLeft + (totalOnes - onesLeft));
    }
    return best;
};
